// Walk the MIME part tree and return ONE ITEM PER PDF found.
// Large PDFs have body.attachmentId; small ones have body.data inline.
// Returning multiple items means all downstream nodes run once per PDF,
// so a multi-leg booking with several PDFs in one email is fully handled.

function findPdfParts(parts, found) {
  if (!parts) return;
  for (const part of parts) {
    const mime = (part.mimeType || '').toLowerCase();
    const fname = (part.filename || '').toLowerCase();
    if (mime.includes('pdf') || fname.endsWith('.pdf')) {
      found.push(part);
    } else {
      findPdfParts(part.parts, found);
    }
  }
}

const msg = $json;
const pdfParts = [];
findPdfParts(msg.payload && msg.payload.parts, pdfParts);

if (pdfParts.length === 0) {
  return [{ json: { messageId: msg.id, found: false, attachmentId: null, inlineData: null } }];
}

return pdfParts.map(part => {
  const body = part.body || {};
  return {
    json: {
      messageId: msg.id,
      found: true,
      attachmentId: body.attachmentId || null,
      inlineData: body.data || null,
      filename: part.filename || 'ticket.pdf',
      mimeType: part.mimeType || 'application/pdf',
    }
  };
});

// Large PDFs: data arrives from the Fetch Attachment Data HTTP response.
// Gmail uses base64url (RFC 4648 §5: - and _ instead of + and /).
// Convert to standard base64 then expose as binary.file.

const pdfInfo = $('Extract PDF Parts').item.json;

const results = [];
for (const item of $input.all()) {
  const base64url = (item.json.data || '').trim();
  if (!base64url) {
    throw new Error('Fetch Attachment Data returned no bytes — check Gmail OAuth2 scope includes gmail.readonly');
  }

  const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
  const buffer = Buffer.from(base64, 'base64');

  const binaryData = await $helpers.prepareBinaryData(
    buffer,
    pdfInfo.filename || 'ticket.pdf',
    pdfInfo.mimeType || 'application/pdf'
  );

  results.push({
    json: { messageId: pdfInfo.messageId },
    binary: { file: binaryData },
  });
}

return results;

// Small PDFs (<~10 KB): body.data is already present inline in the
// full-message response. No separate fetch needed.

const pdfInfo = $input.item.json;
const base64url = (pdfInfo.inlineData || '').trim();
if (!base64url) {
  throw new Error('Expected inline attachment data but body.data was empty');
}

const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
const buffer = Buffer.from(base64, 'base64');

const binaryData = await $helpers.prepareBinaryData(
  buffer,
  pdfInfo.filename || 'ticket.pdf',
  pdfInfo.mimeType || 'application/pdf'
);

return [{
  json: { messageId: pdfInfo.messageId },
  binary: { file: binaryData },
}];
